import React, { useState, useEffect, useMemo } from 'react';
import { View } from 'react-native';
import { KangurMobileAiTutorCard } from '../ai-tutor/KangurMobileAiTutorCard';
import { KangurMobileScrollScreen } from '../shared/KangurMobileUi';
import { useKangurMobileLessonCheckpoints } from './useKangurMobileLessonCheckpoints';
import { useKangurMobileLessonsBadges } from './useKangurMobileLessonsBadges';
import { useKangurMobileLessonsLessonMastery } from './useKangurMobileLessonsLessonMastery';
import { useKangurMobileLessonsRecentResults } from './useKangurMobileLessonsRecentResults';
import { useKangurMobileLessonsAssignments } from './useKangurMobileLessonsAssignments';
import { useKangurMobileLessonsDuels } from './useKangurMobileLessonsDuels';
import { LessonsSecondarySections } from './lessons-screen-secondary-sections';
import { createKangurDuelsHref } from '../duels/duelsHref';
import { LessonsHeader } from './components/LessonsHeader';
import { LessonCard } from './components/LessonCard';
import { useLessonsScreenState } from './useLessonsScreenState';
import { createKangurResultsHref } from '../scores/resultsHref';

export function KangurLessonsScreen(): React.JSX.Element {
  const { copy, router, focusToken, actionError, lessons, saveLessonCheckpoint, selectedLesson, isPreparing, selectedLessonBody } = useLessonsScreenState();

  const lessonCheckpoints = useKangurMobileLessonCheckpoints({ limit: 2 });
  const lessonBadges = useKangurMobileLessonsBadges();
  const lessonMastery = useKangurMobileLessonsLessonMastery();
  const lessonRecentResults = useKangurMobileLessonsRecentResults();
  const lessonsAssignments = useKangurMobileLessonsAssignments();
  const lessonDuels = useKangurMobileLessonsDuels();

  const [dismissedFocusToken, setDismissedFocusToken] = useState<string | null>(null);
  const [savedCheckpoint, setSavedCheckpoint] = useState<any | null>(null);
  const [activeSectionIdx, setActiveSectionIdx] = useState(0);

  useEffect(() => { setActiveSectionIdx(0); }, [selectedLesson?.lesson.id]);

  const effectiveFocusToken = useMemo(() => {
    if (focusToken === null || focusToken === dismissedFocusToken) return null;
    return focusToken;
  }, [focusToken, dismissedFocusToken]);

  const tutorContext = useMemo(() => ({
    contentId: selectedLesson?.lesson.id ?? 'lesson:list',
    focusKind: selectedLessonBody !== null ? 'document' as const : (selectedLesson !== null ? 'lesson_header' as const : 'library' as const),
    focusLabel: selectedLesson?.lesson.title,
    surface: 'lesson' as const,
    title: selectedLesson?.lesson.title ?? copy({ de: 'Lektionen', en: 'Lessons', pl: 'Lekcje' }),
  }), [selectedLesson, selectedLessonBody, copy]);

  return (
    <KangurMobileScrollScreen contentContainerStyle={{ gap: 18, paddingHorizontal: 20, paddingVertical: 24 }}>
      <View style={{ gap: 14 }}>
        <LessonsHeader copy={copy} lessonMastery={lessonMastery as any} planHref="/plan" resultsHref={createKangurResultsHref()} />
        <KangurMobileAiTutorCard context={tutorContext} />
        <LessonCard
            copy={copy}
            isPreparing={isPreparing}
            selectedLesson={selectedLesson}
            focusToken={focusToken}
            selectedLessonBody={selectedLessonBody}
            actionError={actionError}
            savedCheckpoint={savedCheckpoint}
            activeSectionIdx={activeSectionIdx}
            effectiveFocusToken={effectiveFocusToken}
            saveLessonCheckpoint={saveLessonCheckpoint}
            setSavedCheckpoint={setSavedCheckpoint}
            setDismissedFocusToken={setDismissedFocusToken}
            setActiveSectionIdx={setActiveSectionIdx}
            router={router}
        />
        <LessonsSecondarySections
          copy={copy} duelSectionDescription="" isPreparingLessonsView={isPreparing} lessonBadges={lessonBadges} lessonCheckpoints={lessonCheckpoints} lessonDuels={lessonDuels} lessonFocusSummary={null} lessonMastery={lessonMastery as any} lessonRecentResults={lessonRecentResults} lessons={lessons} lessonsAssignments={lessonsAssignments} locale="de"
          onOpenCatalogLesson={() => setDismissedFocusToken(null)} openDuelSession={(id) => router.replace(createKangurDuelsHref({ sessionId: id }))} profileHref="/profile" resultsHref={createKangurResultsHref()}
        />
      </View>
    </KangurMobileScrollScreen>
  );
}

import React from 'react';
import { View, Text } from 'react-native';
import { KangurMobileCard as Card } from '../shared/KangurMobileUi';
import { LessonsAssignmentRow } from './lesson-row-primitives';
import type { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import type { useKangurMobileLessonsAssignments } from './useKangurMobileLessonsAssignments';

type LessonsCopy = ReturnType<typeof useKangurMobileI18n>['copy'];
type LessonsAssignmentsState = ReturnType<typeof useKangurMobileLessonsAssignments>;

export function LessonsAssignmentsPanel({
  copy,
  lessonsAssignments,
}: {
  copy: LessonsCopy;
  lessonsAssignments: LessonsAssignmentsState;
}): React.JSX.Element {
  return (
    <Card>
      <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
        {copy({ de: 'Nach den Lektionen', en: 'After lessons', pl: 'Po lekcjach' })}
      </Text>
      <Text style={{ color: '#0f172a', fontSize: 20, fontWeight: '800' }}>
        {copy({ de: 'Nächste Schritte', en: 'Next steps', pl: 'Kolejne kroki' })}
      </Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {copy({
          de: 'Wandle das Lesen der Lektionen direkt in die nächsten Schritte um, ohne den Lernfluss zu verlieren.',
          en: 'Turn lesson reading directly into the next steps without losing the study flow.',
          pl: 'Zamień czytanie lekcji od razu w kolejne kroki, bez gubienia rytmu nauki.',
        })}
      </Text>

      {lessonsAssignments.assignmentItems.length === 0 ? (
        <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
          {copy({
            de: 'Es gibt noch keine nächsten Schritte.',
            en: 'There are no next steps yet.',
            pl: 'Nie ma jeszcze kolejnych kroków.',
          })}
        </Text>
      ) : (
        <View style={{ gap: 10 }}>
          {lessonsAssignments.assignmentItems.map((item) => (
            <LessonsAssignmentRow key={item.assignment.id} item={item} />
          ))}
        </View>
      )}
    </Card>
  );
}

import React from 'react';
import { Text, View, Pressable } from 'react-native';
import { Link, type Href } from 'expo-router';
import {
  KangurMobileCard as Card,
  KangurMobileInsetPanel as InsetPanel,
  KangurMobileLinkButton as LinkButton,
  KangurMobilePill as Pill,
} from '../shared/KangurMobileUi';
import { getMasteryTone } from './lessons-screen-primitives';
import { getKangurMobileLocaleTag, type KangurMobileLocale } from '../i18n/kangurMobileI18n';
import { type LessonsCatalogPanelProps, type LessonItem } from './lessons-types';

interface LessonCheckpointSummaryProps {
  checkpoint: { lastCompletedAt: string, lastScorePercent: number, bestScorePercent: number };
  copy: (dict: { de: string; en: string; pl: string }) => string;
  locale: KangurMobileLocale;
}

function LessonCheckpointSummary({ checkpoint, copy, locale }: LessonCheckpointSummaryProps): React.JSX.Element {
  const dateStr = new Intl.DateTimeFormat(getKangurMobileLocaleTag(locale), { dateStyle: 'medium', timeStyle: 'short' }).format(new Date(checkpoint.lastCompletedAt));
  return (
    <InsetPanel gap={6} padding={12} style={{ borderRadius: 18, borderColor: '#bfdbfe', backgroundColor: '#eff6ff' }}>
      <Text style={{ color: '#1d4ed8', fontSize: 12, fontWeight: '700' }}>
        {copy({ de: 'Letzter Checkpoint', en: 'Latest checkpoint', pl: 'Ostatni checkpoint' })}
      </Text>
      <Text style={{ color: '#0f172a', fontSize: 13, lineHeight: 18 }}>
        {copy({
          de: `Zuletzt gespeichert ${dateStr}`,
          en: `Last saved ${dateStr}`,
          pl: `Ostatni zapis ${dateStr}`,
        })}
      </Text>
      <Text style={{ color: '#475569', fontSize: 13, lineHeight: 18 }}>
        {copy({ de: `Ergebnis ${checkpoint.lastScorePercent}% • bestes ${checkpoint.bestScorePercent}%`, en: `Score ${checkpoint.lastScorePercent}% • best ${checkpoint.bestScorePercent}%`, pl: `Wynik ${checkpoint.lastScorePercent}% • najlepszy ${checkpoint.bestScorePercent}%` })}
      </Text>
    </InsetPanel>
  );
}

function LessonItemRow({ item, copy, locale, onOpenCatalogLesson }: { item: LessonItem, copy: (dict: { de: string; en: string; pl: string }) => string, locale: KangurMobileLocale, onOpenCatalogLesson: () => void }): React.JSX.Element {
  const masteryTone = getMasteryTone(item.mastery.badgeAccent);
  const href: Href = { pathname: '/lessons', params: { focus: item.lesson.componentId } };

  return (
    <InsetPanel
      key={item.lesson.id}
      gap={10}
      padding={16}
      style={{
        borderRadius: 22,
        borderColor: item.isFocused ? '#1d4ed8' : '#e2e8f0',
        backgroundColor: item.isFocused ? '#eff6ff' : '#f8fafc',
      }}
    >
      <Link href={href} asChild>
        <Pressable accessibilityRole="button" onPress={onOpenCatalogLesson} style={{ gap: 10 }}>
          <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'flex-start', gap: 12 }}>
            <View style={{ flex: 1, gap: 4 }}>
              <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>{item.lesson.emoji} {item.lesson.title}</Text>
              <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>{item.lesson.description}</Text>
            </View>
            <Pill label={item.mastery.statusLabel} tone={masteryTone} />
          </View>
          <Text style={{ color: '#64748b', fontSize: 12, lineHeight: 18 }}>{item.mastery.summaryLabel}</Text>
          {item.checkpointSummary && (
            <LessonCheckpointSummary checkpoint={item.checkpointSummary} copy={copy} locale={locale} />
          )}
        </Pressable>
      </Link>
      <View style={{ flexDirection: 'column', gap: 8 }}>
        <LinkButton href={href} label={`${copy({ de: 'Lektion öffnen', en: 'Open lesson', pl: 'Otwórz lekcję' })}: ${item.lesson.title}`} onPress={onOpenCatalogLesson} stretch textStyle={{ textAlign: 'left' }} tone="primary" />
        {item.practiceHref && (
          <LinkButton href={item.practiceHref as Href} label={`${copy({ de: 'Training starten', en: 'Start practice', pl: 'Uruchom trening' })}: ${item.lesson.title}`} stretch textStyle={{ textAlign: 'left' }} tone="secondary" />
        )}
      </View>
    </InsetPanel>
  );
}

export function LessonsCatalogPanel({
  copy,
  lessons,
  locale,
  onOpenCatalogLesson,
}: LessonsCatalogPanelProps): React.JSX.Element {
  return (
    <Card>
      <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
        {copy({ de: 'Lektionskatalog', en: 'Lesson catalog', pl: 'Katalog lekcji' })}
      </Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
        {copy({
          de: 'Beginne mit neuen Themen oder kehre zu Bereichen zurück, die Wiederholung brauchen.',
          en: 'Start with new topics or return to the areas that need review.',
          pl: 'Zacznij od nowych tematów albo wróć do obszarów wymagających powtórki.',
        })}
      </Text>
      <View style={{ gap: 12 }}>
        {lessons.map((item) => (
          <LessonItemRow key={item.lesson.id} item={item} copy={copy} locale={locale} onOpenCatalogLesson={onOpenCatalogLesson} />
        ))}
      </View>
    </Card>
  );
}

import React from 'react';
import { Text, View } from 'react-native';
import {
  KangurMobileCard as Card,
  KangurMobileInsetPanel as InsetPanel,
  KangurMobilePendingActionButton,
  KangurMobilePill as Pill,
} from '../shared/KangurMobileUi';
import { ActionButton } from './duels-primitives';
import { type UseKangurMobileLearnerDuelsSummaryResult } from '../duels/useKangurMobileLearnerDuelsSummary';
import { type useKangurMobileI18n } from '../i18n/kangurMobileI18n';

export function LessonsDuelsPanel({
  copy,
  duelSectionDescription,
  lessonDuels,
  onRematch,
  pendingOpponentLearnerId,
}: {
  copy: ReturnType<typeof useKangurMobileI18n>['copy'];
  duelSectionDescription: string;
  lessonDuels: UseKangurMobileLearnerDuelsSummaryResult;
  onRematch: (learnerId: string) => Promise<void>;
  pendingOpponentLearnerId: string | null;
}): React.JSX.Element {
  return (
    <Card>
      <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
        {copy({ de: 'Nach der Lektion', en: 'After the lesson', pl: 'Po lekcji' })}
      </Text>
      <Text style={{ color: '#0f172a', fontSize: 20, fontWeight: '800' }}>
        {copy({ de: 'Schneller Rückweg zu Rivalen', en: 'Quick return to rivals', pl: 'Szybki powrót do rywali' })}
      </Text>
      <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>{duelSectionDescription}</Text>

      <View style={{ flexDirection: 'row', flexWrap: 'wrap', gap: 8, marginTop: 12 }}>
        <Pill
          label={copy({ de: `Rivalen ${lessonDuels.opponents.length}`, en: `Rivals ${lessonDuels.opponents.length}`, pl: `Rywale ${lessonDuels.opponents.length}` })}
          tone={{ backgroundColor: '#eef2ff', borderColor: '#c7d2fe', textColor: '#4338ca' }}
        />
        {lessonDuels.currentRank !== null && (
          <Pill
            label={`#${lessonDuels.currentRank}`}
            tone={{ backgroundColor: '#fef3c7', borderColor: '#fde68a', textColor: '#b45309' }}
          />
        )}
      </View>

      <View style={{ gap: 12, marginTop: 12 }}>
        {lessonDuels.opponents.map((opponent) => (
          <InsetPanel key={opponent.learnerId} gap={6} padding={12} style={{ borderRadius: 18, backgroundColor: '#ffffff' }}>
            <Text style={{ color: '#0f172a', fontSize: 15, fontWeight: '800' }}>{opponent.displayName}</Text>
            <KangurMobilePendingActionButton
              label={copy({ de: 'Schneller Rewatch', en: 'Quick rematch', pl: 'Szybki rewanż' })}
              onPress={() => { void onRematch(opponent.learnerId); }}
              pending={pendingOpponentLearnerId === opponent.learnerId}
            />
          </InsetPanel>
        ))}
        {lessonDuels.error !== null && (
            <View style={{ gap: 10 }}>
                <Text style={{ color: '#b91c1c' }}>{lessonDuels.error}</Text>
                <ActionButton label={copy({ de: 'Aktualisieren', en: 'Refresh', pl: 'Odśwież' })} onPress={() => { void lessonDuels.refresh(); }} />
            </View>
        )}
      </View>
    </Card>
  );
}

import React from 'react';
import { Text, View } from 'react-native';
import {
  KangurMobileActionButton as ActionButton,
  KangurMobileFilterChip as FilterChip,
  KangurMobileInsetPanel as InsetPanel,
} from '../shared/KangurMobileUi';
import { type LessonBody } from './lessons-types';

export function LessonBodyView({
  copy,
  lessonBody,
  activeSectionIndex,
  setActiveSectionIndex,
  onSave,
}: {
  copy: (dict: { de: string; en: string; pl: string }) => string;
  lessonBody: LessonBody;
  activeSectionIndex: number;
  setActiveSectionIndex: (index: number) => void;
  onSave: () => void;
}): React.JSX.Element {
  const activeSection = lessonBody.sections[activeSectionIndex] ?? null;
  const totalSections = lessonBody.sections.length;

  return (
    <View style={{ gap: 12 }}>
      <Text style={{ color: '#475569', fontSize: 14 }}>{lessonBody.introduction}</Text>
      <View style={{ gap: 8 }}>
        <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>
          {copy({ de: 'Lektionsabschnitte', en: 'Lesson sections', pl: 'Sekcje lekcji' })}
        </Text>
        <View style={{ flexDirection: 'column', gap: 8 }}>
          {lessonBody.sections.map((s, idx) => (
            <FilterChip
              key={s.id}
              label={`${idx + 1}. ${s.title}`}
              onPress={() => setActiveSectionIndex(idx)}
              selected={idx === activeSectionIndex}
            />
          ))}
        </View>
      </View>
      {activeSection !== null && (
        <InsetPanel gap={10}>
          <Text style={{ color: '#0f172a', fontSize: 18, fontWeight: '800' }}>{activeSection.title}</Text>
          <Text style={{ color: '#475569', fontSize: 14 }}>{activeSection.description}</Text>
          <View style={{ flexDirection: 'row', gap: 10 }}>
            <ActionButton
              centered
              disabled={activeSectionIndex === 0}
              label={copy({ de: 'Zurück', en: 'Previous', pl: 'Poprzednia' })}
              onPress={() => setActiveSectionIndex(Math.max(0, activeSectionIndex - 1))}
              tone="secondary"
            />
            <ActionButton
              centered
              disabled={activeSectionIndex >= totalSections - 1}
              label={copy({ de: 'Weiter', en: 'Next', pl: 'Następna' })}
              onPress={() => setActiveSectionIndex(Math.min(totalSections - 1, activeSectionIndex + 1))}
              tone="primary"
            />
          </View>
        </InsetPanel>
      )}
      {Boolean(lessonBody.practiceNote) && (
        <Text style={{ color: '#475569', fontSize: 13, fontStyle: 'italic', lineHeight: 18 }}>
          {lessonBody.practiceNote}
        </Text>
      )}

      <ActionButton
        centered
        label={copy({ de: 'Zapisz checkpoint', en: 'Save checkpoint', pl: 'Zapisz checkpoint' })}
        onPress={onSave}
        stretch
        tone="primary"
      />
    </View>
  );
}

import React from 'react';
import { Text, View } from 'react-native';
import {
  KangurMobileActionButton as ActionButton,
  KangurMobileCard as Card,
  KangurMobileInsetPanel as InsetPanel,
  KangurMobileLinkButton as LinkButton,
  KangurMobilePill as Pill,
} from '../../shared/KangurMobileUi';
import { type LessonBody } from './lessons-types';
import { LessonBodyView } from './LessonBodyView';
import { type Href } from 'expo-router';

interface SavedCheckpoint {
  countsAsLessonCompletion: boolean;
  newBadges: string[];
  scorePercent: number;
}

interface Lesson {
  emoji: string;
  title: string;
  componentId: string;
  description: string;
}

interface CheckpointSummary {
  attempts: number;
  bestScorePercent: number;
  lastScorePercent: number;
  lastCompletedAt: string;
}

interface SelectedLesson {
  lesson: Lesson;
  checkpointSummary?: CheckpointSummary;
}

interface LessonCardProps {
  copy: (dict: { de: string; en: string; pl: string }) => string;
  isPreparing: boolean;
  selectedLesson: SelectedLesson | null;
  focusToken: string | null;
  selectedLessonBody: LessonBody | null;
  actionError: string | null;
  savedCheckpoint: SavedCheckpoint | null;
  activeSectionIdx: number;
  effectiveFocusToken: string | null;
  saveLessonCheckpoint: (checkpoint: { countsAsLessonCompletion: boolean, lessonComponentId: string, scorePercent: number }) => SavedCheckpoint;
  setSavedCheckpoint: (checkpoint: SavedCheckpoint | null) => void;
  setDismissedFocusToken: (token: string | null) => void;
  setActiveSectionIdx: (idx: number) => void;
  router: any;
}

export function LessonCard(props: LessonCardProps): React.JSX.Element | null {
  const { isPreparing, selectedLesson, focusToken } = props;

  if (isPreparing) return (selectedLesson !== null || focusToken !== null) ? <View /> : null;
  if (selectedLesson === null) return <LessonShortcutHelp {...props} />;

  return <LessonDetailsCard {...props} selectedLesson={selectedLesson} />;
}

function LessonShortcutHelp({ copy, focusToken, setDismissedFocusToken, router }: LessonCardProps): React.JSX.Element {
  return (
    <Card>
      <Text style={{ color: '#0f172a', fontSize: 24, fontWeight: '800' }}>
        {copy({ de: 'Lektions-Shortcut', en: 'Lesson shortcut', pl: 'Skrót do lekcji' })}
      </Text>
      <InsetPanel gap={10}>
        <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>
          {copy({
            de: `Der Shortcut wollte "${focusToken}" öffnen. Dieser Shortcut öffnet "${focusToken}" nicht mehr.`,
            en: `The shortcut tried to open "${focusToken}". This shortcut no longer opens "${focusToken}".`,
            pl: `Skrót próbował otworzyć "${focusToken}". Ten skrót już nie otwiera "${focusToken}".`,
          })}
        </Text>
      </InsetPanel>
      <View style={{ gap: 10 }}>
        <LinkButton href="/lessons" label={copy({ de: 'Otwórz pełny katalog', en: 'Open full catalog', pl: 'Otwórz pełny katalog' })} stretch tone="primary" />
        <ActionButton
          label={copy({ de: 'Zurück zur Liste', en: 'Back to list', pl: 'Wróć do listy' })}
          onPress={() => {
            if (focusToken) setDismissedFocusToken(focusToken);
            router.replace('/lessons');
          }}
          stretch
          tone="secondary"
        />
      </View>
    </Card>
  );
}

interface LessonDetailsCardProps extends LessonCardProps {
  selectedLesson: SelectedLesson;
}

function LessonDetailsCard(props: LessonDetailsCardProps): React.JSX.Element {
  const { copy, selectedLesson, actionError, savedCheckpoint, selectedLessonBody, activeSectionIdx, effectiveFocusToken, saveLessonCheckpoint, setSavedCheckpoint, setActiveSectionIdx, setDismissedFocusToken, router, focusToken } = props;

  return (
    <Card>
      <Text style={{ color: '#0f172a', fontSize: 24, fontWeight: '800' }}>{selectedLesson.lesson.emoji} {selectedLesson.lesson.title}</Text>
      {actionError && <Text style={{ color: '#b91c1c', fontSize: 14 }}>{actionError}</Text>}
      {savedCheckpoint && (
        <InsetPanel gap={8} style={{ backgroundColor: '#f0fdfa', borderColor: '#ccfbf1' }}>
          <Text style={{ color: '#0f766e', fontSize: 14, lineHeight: 20 }}>
            {savedCheckpoint.countsAsLessonCompletion
              ? copy({ de: `Lektion mit ${savedCheckpoint.scorePercent}% abgeschlossen!`, en: `Lesson completed with ${savedCheckpoint.scorePercent}%!`, pl: `Lekcja ukończona z wynikiem ${savedCheckpoint.scorePercent}%!` })
              : copy({ de: `Checkpoint mit ${savedCheckpoint.scorePercent}% gespeichert.`, en: `Checkpoint saved with ${savedCheckpoint.scorePercent}%!`, pl: `Checkpoint lekcji zapisano lokalnie z wynikiem ${savedCheckpoint.scorePercent}%.` })}
          </Text>
          {savedCheckpoint.newBadges.length > 0 && (
            <Text style={{ color: '#0d9488', fontSize: 13, fontWeight: '700' }}>
              {copy({ de: 'Neue Abzeichen', en: 'New badges', pl: 'Nowa odznaka' })}: {savedCheckpoint.newBadges.join(', ')}
            </Text>
          )}
        </InsetPanel>
      )}

      {selectedLessonBody !== null ? (
        <View style={{ gap: 16 }}>
          <View style={{ gap: 4 }}>
            <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>{copy({ de: 'Ausgewählte Lektion', en: 'Selected lesson', pl: 'Wybrana lekcja' })}</Text>
            <Text style={{ color: '#475569', fontSize: 13, lineHeight: 18 }}>{copy({ de: `Aktuell geöffnet: ${selectedLesson.lesson.title}.`, en: `Currently open: ${selectedLesson.lesson.title}.`, pl: `Aktualnie otwarte: ${selectedLesson.lesson.title}.` })}</Text>
          </View>
          <LessonBodyView
            activeSectionIndex={activeSectionIdx}
            copy={copy}
            lessonBody={selectedLessonBody}
            onSave={() => {
              const res = saveLessonCheckpoint({
                countsAsLessonCompletion: activeSectionIdx >= selectedLessonBody.sections.length - 1,
                lessonComponentId: selectedLesson.lesson.componentId,
                scorePercent: Math.round(((activeSectionIdx + 1) / selectedLessonBody.sections.length) * 100),
              });
              setSavedCheckpoint(res);
            }}
            setActiveSectionIndex={setActiveSectionIdx}
          />
          <InsetPanel gap={8} style={{ backgroundColor: '#f0f9ff', borderColor: '#bae6fd' }}>
            <View style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 8 }}>
              <Text style={{ color: '#0369a1', fontSize: 12, fontWeight: '700' }}>{copy({ de: 'Lektionsfortschritt', en: 'Lesson progress', pl: 'Postęp lekcji' })}</Text>
              <View style={{ flexDirection: 'row', gap: 8 }}>
                {effectiveFocusToken !== null && <Pill label={copy({ de: 'Über Shortcut geöffnet', en: 'Opened from shortcut', pl: 'Otwarte ze skrótu' })} tone={{ backgroundColor: '#eef2ff', borderColor: '#c7d2fe', textColor: '#4338ca' }} />}
                <Pill label={`${Math.round(((activeSectionIdx + 1) / selectedLessonBody.sections.length) * 100)}%`} tone={{ backgroundColor: '#ffffff', borderColor: '#7dd3fc', textColor: '#0369a1' }} />
              </View>
            </View>
          </InsetPanel>
        </View>
      ) : (
        <View style={{ gap: 12 }}>
          <InsetPanel gap={10}>
            <Text style={{ color: '#64748b', fontSize: 12, fontWeight: '700' }}>{copy({ de: 'Lektionsbrief', en: 'Lesson brief', pl: 'Skrót lekcji' })}</Text>
            <Text style={{ color: '#475569', fontSize: 14, lineHeight: 20 }}>{copy({ de: 'Diese Lektion ist hier vorerst als Kurzbrief verfügbar.', en: 'This lesson is currently available here as a brief summary.', pl: 'Ta lekcja jest tu na razie dostępna jako krótki skrót.' })}</Text>
          </InsetPanel>

          <View style={{ gap: 8 }}>
            <Text style={{ color: '#475569', fontSize: 14 }}>{copy({ de: 'Versuche', en: 'Attempts', pl: 'Próby' })} {selectedLesson.checkpointSummary?.attempts ?? 0}</Text>
            <Text style={{ color: '#475569', fontSize: 14 }}>{copy({ de: 'Bestes Ergebnis', en: 'Best score', pl: 'Najlepszy wynik' })} {selectedLesson.checkpointSummary?.bestScorePercent ?? 0}%</Text>
            <Text style={{ color: '#475569', fontSize: 14 }}>{copy({ de: 'Letztes Ergebnis', en: 'Last score', pl: 'Ostatni wynik' })} {selectedLesson.checkpointSummary?.lastScorePercent ?? 0}%</Text>
            {selectedLesson.checkpointSummary?.lastCompletedAt && (
              <Text style={{ color: '#64748b', fontSize: 12 }}>{copy({ de: 'Letzte Speicherung', en: 'Last saved', pl: 'Ostatni zapis' })}: {new Date(selectedLesson.checkpointSummary.lastCompletedAt).toLocaleDateString()}</Text>
            )}
          </View>
          <ActionButton
            label={copy({ de: 'Zapisz checkpoint', en: 'Save checkpoint', pl: 'Zapisz checkpoint' })}
            onPress={() => {
              const res = saveLessonCheckpoint({
                countsAsLessonCompletion: false,
                lessonComponentId: selectedLesson.lesson.componentId,
                scorePercent: 50,
              });
              setSavedCheckpoint(res);
            }}
            stretch
            tone="primary"
          />
        </View>
      )}

      <ActionButton
        label={copy({ de: 'Zurück zur Liste', en: 'Back to list', pl: 'Wróć do listy' })}
        onPress={() => {
          if (focusToken !== null) setDismissedFocusToken(focusToken);
          router.replace('/lessons');
        }}
        stretch
        tone="secondary"
      />
    </Card>
  );
}

