type LessonCheckpointEntry = [
  componentId: string,
  mastery: KangurProgressState['lessonMastery'][string],
];

const resolveTimestamp = (value: string | null): number => {
  if (!value) {
    return Number.NEGATIVE_INFINITY;
  }

  const parsed = Date.parse(value);
  return Number.isFinite(parsed) ? parsed : Number.NEGATIVE_INFINITY;
};

const compareLessonCheckpointEntries = (
  [leftComponentId, leftMastery]: LessonCheckpointEntry,
  [rightComponentId, rightMastery]: LessonCheckpointEntry,
): number => {
  const timestampDelta =
    resolveTimestamp(rightMastery.lastCompletedAt) - resolveTimestamp(leftMastery.lastCompletedAt);
  if (timestampDelta !== 0) {
    return timestampDelta;
  }

  if (rightMastery.lastScorePercent !== leftMastery.lastScorePercent) {
    return rightMastery.lastScorePercent - leftMastery.lastScorePercent;
  }

  return leftComponentId.localeCompare(rightComponentId);
};

const selectRecentCheckpointEntries = (
  lessonMastery: KangurProgressState['lessonMastery'],
  limit: number,
): LessonCheckpointEntry[] => {
  const recentEntries: LessonCheckpointEntry[] = [];

  for (const [componentId, mastery] of Object.entries(lessonMastery)) {
    if (typeof mastery.lastCompletedAt !== 'string') {
      continue;
    }

    const candidateEntry: LessonCheckpointEntry = [componentId, mastery];
    const insertIndex = recentEntries.findIndex(
      (entry) => compareLessonCheckpointEntries(candidateEntry, entry) < 0,
    );

    if (insertIndex === -1) {
      recentEntries.push(candidateEntry);
    } else {
      recentEntries.splice(insertIndex, 0, candidateEntry);
    }

    if (recentEntries.length > limit) {
      recentEntries.length = limit;
    }
  }

  return recentEntries;
};

export const getKangurMobileLessonCheckpoints = (
  progress: KangurProgressState,
  locale: string | null | undefined,
  options: UseKangurMobileLessonCheckpointsOptions = {},
): UseKangurMobileLessonCheckpointsResult => {
  const limit =
    typeof options.limit === 'number' && options.limit > 0
      ? Math.round(options.limit)
      : 2;

  return {
    recentCheckpoints: selectRecentCheckpointEntries(progress.lessonMastery, limit).map(
      ([componentId, mastery]) => {
        const lessonCatalogEntry = KANGUR_LESSON_CATALOG[componentId];
        const practiceOperation = getKangurPracticeOperationForLessonComponent(
          componentId as Parameters<
            typeof getKangurPracticeOperationForLessonComponent
          >[0],
        );

        return {
          attempts: mastery.attempts,
          bestScorePercent: mastery.bestScorePercent,
          componentId,
          emoji: lessonCatalogEntry?.emoji ?? '📘',
          lastCompletedAt: mastery.lastCompletedAt as string,
          lastScorePercent: mastery.lastScorePercent,
          lessonHref: createKangurLessonHref(componentId),
          masteryPercent: mastery.masteryPercent,
          practiceHref: practiceOperation ? createKangurPracticeHref(practiceOperation) : null,
          title: getLocalizedKangurCoreLessonTitle(
            componentId,
            locale,
            lessonCatalogEntry?.title,
          ),
        };
      },
    ),
  };
};

export const useKangurMobileLessonCheckpoints = (
  options: UseKangurMobileLessonCheckpointsOptions = {},
): UseKangurMobileLessonCheckpointsResult => {
  const { locale } = useKangurMobileI18n();
  const { progressStore } = useKangurMobileRuntime();
  const progress = useSyncExternalStore(
    progressStore.subscribeToProgress,
    progressStore.loadProgress,
    createDefaultKangurProgressState,
  );
  const recentCheckpoints = useMemo(
    () => getKangurMobileLessonCheckpoints(progress, locale, options).recentCheckpoints,
    [locale, options.limit, progress],
  );

  return {
    recentCheckpoints,
  };
};

import {
  getKangurLessonMasteryPresentation,
  getLocalizedKangurPortableLessons,
  resolveFocusedKangurLessonId,
  type KangurLessonMasteryPresentation,
  type KangurPortableLesson,
  getKangurPracticeOperationForLessonComponent,
  type KangurProgressState,
} from '@kangur/core';
import { createDefaultKangurProgressState, type KangurLessonMasteryEntry } from '@kangur/contracts/kangur';
import type { Href } from 'expo-router';
import { useMemo, useState, useSyncExternalStore, useCallback } from 'react';

import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { createKangurPracticeHref } from '../practice/practiceHref';
import { useKangurMobileRuntime } from '../providers/KangurRuntimeContext';
import { saveLessonCheckpoint, type SaveLessonCheckpointInput } from './lesson-checkpoint-service';
import type { KangurMobileLocale } from '../i18n/kangurMobileI18n';

export type KangurMobileLessonItem = {
  checkpointSummary: {
    attempts: number;
    bestScorePercent: number;
    lastCompletedAt: string;
    lastScorePercent: number;
    masteryPercent: number;
  } | null;
  isFocused: boolean;
  lesson: KangurPortableLesson;
  mastery: KangurLessonMasteryPresentation;
  practiceHref: Href | null;
};

type UseKangurMobileLessonsResult = {
  actionError: string | null;
  focusToken: string | null;
  lessons: KangurMobileLessonItem[];
  saveLessonCheckpoint: (input: SaveLessonCheckpointInput) => {
    countsAsLessonCompletion: boolean;
    newBadges: string[];
    scorePercent: number;
  } | null;
  selectedLesson: KangurMobileLessonItem | null;
};

const transformLesson = (
  lesson: KangurPortableLesson,
  progress: KangurProgressState,
  locale: KangurMobileLocale,
  selectedLessonId: string | null
): KangurMobileLessonItem => {
  const checkpoint = progress.lessonMastery[lesson.componentId] as KangurLessonMasteryEntry | undefined;
  const practiceOperation = getKangurPracticeOperationForLessonComponent(lesson.componentId);

  let checkpointSummary: KangurMobileLessonItem['checkpointSummary'] = null;
  if (checkpoint && typeof checkpoint.lastCompletedAt === 'string') {
    checkpointSummary = {
      attempts: checkpoint.attempts,
      bestScorePercent: checkpoint.bestScorePercent,
      lastCompletedAt: checkpoint.lastCompletedAt,
      lastScorePercent: checkpoint.lastScorePercent,
      masteryPercent: checkpoint.masteryPercent,
    };
  }

  return {
    checkpointSummary,
    isFocused: lesson.id === selectedLessonId,
    lesson,
    mastery: getKangurLessonMasteryPresentation(lesson, progress, locale),
    practiceHref: practiceOperation ? createKangurPracticeHref(practiceOperation) : null,
  };
};

export const useKangurMobileLessons = (
  rawFocusToken: string | null,
): UseKangurMobileLessonsResult => {
  const { copy, locale } = useKangurMobileI18n();
  const { progressStore } = useKangurMobileRuntime();
  const [actionError, setActionError] = useState<string | null>(null);
  const progress = useSyncExternalStore(
    progressStore.subscribeToProgress,
    progressStore.loadProgress,
    createDefaultKangurProgressState,
  );
  const focusToken = rawFocusToken !== null ? rawFocusToken.trim().toLowerCase() : null;
  const portableLessons = useMemo(() => getLocalizedKangurPortableLessons(locale), [locale]);

  const selectedLessonId = useMemo(
    () =>
      focusToken !== null
        ? resolveFocusedKangurLessonId(focusToken, portableLessons)
        : null,
    [focusToken, portableLessons],
  );

  const lessons = useMemo(
    () => portableLessons.map((lesson) => transformLesson(lesson, progress, locale, selectedLessonId)),
    [locale, portableLessons, progress, selectedLessonId],
  );

  const handleSaveLessonCheckpoint = useCallback((input: SaveLessonCheckpointInput) => {
    const normalizedLessonComponentId = input.lessonComponentId.trim();
    if (normalizedLessonComponentId === '') {
      setActionError(copy({ de: 'Diese Lektion konnte lokal nicht gespeichert werden.', en: 'Could not save this lesson locally.', pl: 'Nie udało się zapisać tej lekcji lokalnie.' }));
      return null;
    }
    try {
      const result = saveLessonCheckpoint(input, progress, progressStore);
      setActionError(null);
      return result;
    } catch {
      setActionError(copy({ de: 'Diese Lektion konnte lokal nicht gespeichert werden.', en: 'Could not save this lesson locally.', pl: 'Nie udało się zapisać tej lekcji lokalnie.' }));
      return null;
    }
  }, [copy, progress, progressStore]);

  return {
    actionError,
    focusToken,
    lessons,
    saveLessonCheckpoint: handleSaveLessonCheckpoint,
    selectedLesson: lessons.find((lesson) => lesson.isFocused) ?? null,
  };
};

import { useKangurMobileLearnerDuelsSummary } from '../duels/useKangurMobileLearnerDuelsSummary';

const MOBILE_LESSONS_DUELS_LEADERBOARD_LIMIT = 5;
const MOBILE_LESSONS_DUELS_LEADERBOARD_LOOKBACK_DAYS = 14;
const MOBILE_LESSONS_DUELS_OPPONENTS_LIMIT = 2;

export const useKangurMobileLessonsDuels = () =>
  useKangurMobileLearnerDuelsSummary({
    leaderboardLimit: MOBILE_LESSONS_DUELS_LEADERBOARD_LIMIT,
    leaderboardLookbackDays: MOBILE_LESSONS_DUELS_LEADERBOARD_LOOKBACK_DAYS,
    opponentsLimit: MOBILE_LESSONS_DUELS_OPPONENTS_LIMIT,
  });

import { useMemo } from 'react';
import { useLocalSearchParams, useRouter } from 'expo-router';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileLessons } from './useKangurMobileLessons';
import { useLessonsScreenBootState } from './useLessonsScreenBootState';
import { getKangurPortableLessonBody } from '@kangur/core';
import { type LessonBody } from './lessons-types';

export function useLessonsScreenState() {
  const { copy, locale } = useKangurMobileI18n();
  const router = useRouter();
  const params = useLocalSearchParams<{ focus?: string | string[] }>();

  const rawFocusParam = Array.isArray(params.focus) ? params.focus[0] : params.focus;
  const focusToken = (typeof rawFocusParam === 'string' && rawFocusParam.trim() !== '') ? rawFocusParam.trim().toLowerCase() : null;

  const { actionError, lessons, saveLessonCheckpoint, selectedLesson } = useKangurMobileLessons(focusToken);
  const isPreparing = useLessonsScreenBootState(focusToken ?? 'catalog');

  const selectedLessonBody = useMemo(() => (!isPreparing && selectedLesson !== null) ? getKangurPortableLessonBody(selectedLesson.lesson.componentId, locale) as LessonBody : null, [isPreparing, selectedLesson, locale]);

  return {
    copy,
    router,
    focusToken,
    actionError,
    lessons,
    saveLessonCheckpoint,
    selectedLesson,
    isPreparing,
    selectedLessonBody,
  };
}

import { useMemo } from 'react';
import { useKangurMobileI18n } from '../i18n/kangurMobileI18n';
import { useKangurMobileLessonsLessonMastery } from './useKangurMobileLessonsLessonMastery';
import { type LessonViewModel } from './lessons-types';

export function useLessonsViewModel(): LessonViewModel {
  const { copy, locale } = useKangurMobileI18n();
  const lessonMastery = useKangurMobileLessonsLessonMastery();

  const tutorContext = useMemo(() => ({
    contentId: 'lesson:list',
    focusKind: 'library' as const,
    surface: 'lesson' as const,
    title: copy({ de: 'Lektionen', en: 'Lessons', pl: 'Lekcje' }),
  }), [copy]);

  return {
    copy,
    locale,
    lessonMastery: lessonMastery as any, // Simplified for now, will type properly next
    tutorContext,
  };
}
